B.WL=new A.l(2001,4,2,"\uba54\uc774\uc800\ub9ac\uadf8","\uc774\uce58\ub85c, \uc77c\ubcf8\uc778 \uc57c\uc218 \uccab \ube45\ub9ac\uadf8 \ub370\ubdd4","\uc77c\ubcf8 \uc2a4\ud0c0 \uc774\uce58\ub85c\uac00 \uc2dc\uc560\ud2c0\uc5d0\uc11c \uba54\uc774\uc800\ub9ac\uadf8\uc5d0 \ub370\ubdd4\ud588\ub2e4. \uc544\uc2dc\uc544 \uc120\uc218\uc758 \uc0c8 \uae38\uc774 \uc5f4\ub838\ub2e4.","\uac80\uc99d\ub418\uc9c0 \uc54a\uc740 \ub3c4\uc804\uc774 \uc0c8 \uc2dc\uc7a5\uc744 \uc5fd\ub2c8\ub2e4.",B.q)
